10	-- This component convertes polar coordinates to cartesian coordinates using
11	-- a vectoring CORDIC kernel. In pipelined mode it requires more logic but
12	-- can take one input sample every clock cycle. In serial mode it requires
13	-- N clock cycles but requires less logic.
14	------------------------------------------------------------------------------
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.numeric_std.all;
19	use ieee.math_real.all;
20	
21	use work.psi_fix_pkg.all;
22	use work.psi_common_array_pkg.all;
23	use work.psi_common_math_pkg.all;
24	-- @formatter:off
25	-- $$ processes=stim, resp $$
26	entity psi_fix_cordic_rot is
27	  generic(
28	    in_abs_fmt_g    : psi_fix_fmt_t := (0, 0, 15);                              -- Must be unsigned     $$ constant=(0,0,16) $$
29	    in_angle_fmt_g  : psi_fix_fmt_t := (0, 0, 15);                              -- Must be unsigned     $$ constant=(0,0,15) $$
30	    out_fmt_g       : psi_fix_fmt_t := (1, 2, 16);                              -- Usually signed        $$ constant=(1,2,16) $$
31	    internal_fmt_g  : psi_fix_fmt_t := (1, 2, 22);                              -- Must be signed        $$ constant=(1,2,22) $$
32	    angle_int_fmt_g : psi_fix_fmt_t := (1, -2, 18);                             -- Must be (1, -2, x)   $$ constant=(1,-2,23) $$
33	    iterations_g    : natural     := 13;                                        -- iterative required   $$ constant=21 $$
34	    gain_comp_g     : boolean     := False;                                     -- gain compensation    $$ export=true $$
35	    round_g         : psi_fix_rnd_t := psi_fix_trunc;                           -- round or trunc       $$ export=true $$
36	    sat_g           : psi_fix_sat_t := psi_fix_wrap;                            -- sat or wrap          $$ export=true $$
37	    mode_g          : string      := "SERIAL"                                   -- PIPELINED or SERIAL  $$ export=true $$
38	  );
39	  port(
40	    clk_i       : in  std_logic;                                                   -- clk system $$ type=clk; freq=100e6 $$
41	    rst_i       : in  std_logic;                                                   -- rst system $$ type=rst; clk=Clk $$
42	    dat_abs_i   : in  std_logic_vector(psi_fix_size(in_abs_fmt_g) - 1 downto 0);   -- amplitude signal input
43	    dat_ang_i   : in  std_logic_vector(psi_fix_size(in_angle_fmt_g) - 1 downto 0); -- phase signal input
44	    vld_i       : in  std_logic;                                                   -- valid input
45	    rdy_i       : out std_logic;                                                   -- ready output signal $$ lowactive=true $$
46	    dat_inp_o   : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);      -- dat inphase out
47	    dat_qua_o   : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);      -- dat quadrature out
48	    vld_o       : out std_logic                                                    -- valid output
49	  );
50	end entity;
51	-- @formatter:on
52	
53	architecture rtl of psi_fix_cordic_rot is
54	
55	  -- *** Constants ***
56	  constant AngleTableReal_c : t_areal(0 to 31) := (0.125, 0.0737918088252, 0.0389895651887, 0.0197917120803,
57	                                                   0.00993426215277, 0.00497197391179, 0.00248659363948, 0.00124337269683,
58	                                                   0.000621695834357, 0.000310849102962, 0.000155424699705, 7.77123683806e-05,
59	                                                   3.88561865063e-05, 1.94280935426e-05, 9.71404680751e-06, 4.85702340828e-06,
60	                                                   2.4285117047e-06, 1.21425585242e-06, 6.0712792622e-07, 3.03563963111e-07,
61	                                                   1.51781981556e-07, 7.58909907779e-08, 3.7945495389e-08, 1.89727476945e-08,
62	                                                   9.48637384724e-09, 4.74318692362e-09, 2.37159346181e-09, 1.1857967309e-09,
63	                                                   5.92898365452e-10, 2.96449182726e-10, 1.48224591363e-10, 7.41122956816e-11);
64	  type AngleTable_t is array (0 to iterations_g - 1) of std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0);
65	
66	  function AngleTableStdlv return AngleTable_t is
67	    variable Table : AngleTable_t;
68	  begin
69	    for i in 0 to iterations_g - 1 loop
70	      Table(i) := psi_fix_from_real(AngleTableReal_c(i), angle_int_fmt_g);
71	    end loop;
72	    return Table;
73	  end function;
74	
75	  constant AngleTable_c : AngleTable_t := AngleTableStdlv;
76	
77	  function CordicGain(iterations : integer) return real is
78	    variable g : real := 1.0;
79	  begin
80	    for i in 0 to iterations - 1 loop
81	      g := g * sqrt(1.0 + 2.0**(-2.0 * real(i)));
82	    end loop;
83	    return g;
84	  end function;
85	
86	  constant GcFmt_c        : psi_fix_fmt_t                                        := (0, 0, 17);
87	  constant AngleIntExtFmt : psi_fix_fmt_t                                        := (angle_int_fmt_g.S, max(angle_int_fmt_g.I, 1), angle_int_fmt_g.F);
88	  constant GcCoef_c       : std_logic_vector(psi_fix_size(GcFmt_c) - 1 downto 0) := psi_fix_from_real(1.0 / CordicGain(iterations_g), GcFmt_c);
89	  constant QuadFmt_c      : psi_fix_fmt_t                                        := (0, 0, 2);
90	
91	  -- *** Functions ***
92	  -- Cordic step for X
93	  function CordicStepX(xLast : std_logic_vector;
94	                       yLast : std_logic_vector;
95	                       zLast : std_logic_vector;
96	                       shift : integer) return std_logic_vector is
97	    constant yShifted : std_logic_vector := psi_fix_shift_right(yLast, internal_fmt_g, shift, iterations_g - 1, internal_fmt_g, psi_fix_trunc, psi_fix_wrap, true);
98	  begin
99	
100	    if signed(zLast) > 0 then
101	      return psi_fix_sub(xLast, internal_fmt_g,
102	                       yShifted, internal_fmt_g,
103	                       internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
104	    else
105	      return psi_fix_add(xLast, internal_fmt_g,
106	                       yShifted, internal_fmt_g,
107	                       internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
108	
109	    end if;
110	  end function;
111	
112	  -- Cordic step for Y
113	  function CordicStepY(xLast : std_logic_vector;
114	                       yLast : std_logic_vector;
115	                       zLast : std_logic_vector;
116	                       shift : integer) return std_logic_vector is
117	    constant xShifted : std_logic_vector := psi_fix_shift_right(xLast, internal_fmt_g, shift, iterations_g - 1, internal_fmt_g, psi_fix_trunc, psi_fix_wrap, true);
118	  begin
119	
120	    if signed(zLast) > 0 then
121	      return psi_fix_add(yLast, internal_fmt_g,
122	                       xShifted, internal_fmt_g,
123	                       internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
124	    else
125	      return psi_fix_sub(yLast, internal_fmt_g,
126	                       xShifted, internal_fmt_g,
127	                       internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
128	    end if;
129	  end function;
130	
131	  -- Cordic step for Z
132	  function CordicStepZ(zLast     : std_logic_vector;
133	                       iteration : integer) return std_logic_vector is
134	    constant Atan_c : std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0) := AngleTable_c(iteration);
135	  begin
136	    if signed(zLast) > 0 then
137	      return psi_fix_sub(zLast, angle_int_fmt_g,
138	                       Atan_c, angle_int_fmt_g,
139	                       angle_int_fmt_g, psi_fix_trunc, psi_fix_wrap);
140	    else
141	      return psi_fix_add(zLast, angle_int_fmt_g,
142	                       Atan_c, angle_int_fmt_g,
143	                       angle_int_fmt_g, psi_fix_trunc, psi_fix_wrap);
144	    end if;
145	  end function;
146	
147	  -- Types
148	  type IntArr_t is array (natural range <>) of std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
149	  type AngArr_t is array (natural range <>) of std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0);
150	
151	begin
152	  --------------------------------------------
153	  -- Assertions
154	  --------------------------------------------
155	  assert in_angle_fmt_g.S /= 1 report "psi_fix_cordic_rot: in_angle_fmt_g must be unsigned" severity error;
156	  assert angle_int_fmt_g.S = 1 report "psi_fix_cordic_rot: angle_int_fmt_g must be signed" severity error;
157	  assert angle_int_fmt_g.I = -2 report "psi_fix_cordic_rot: angle_int_fmt_g must be (1,-2,x)" severity error;
158	  assert in_abs_fmt_g.S /= 1 report "psi_fix_cordic_rot: in_abs_fmt_g must be unsigned" severity error;
159	  assert internal_fmt_g.S = 1 report "psi_fix_cordic_rot: internal_fmt_g must be signed" severity error;
160	  assert mode_g = "PIPELINED" or mode_g = "SERIAL" report "psi_fix_cordic_rot: mode_g must be PIPELINED or SERIAL" severity error;
161	  assert internal_fmt_g.I > in_abs_fmt_g.I report "psi_fix_cordic_rot: internal_fmt_g must have at least one more bit than in_abs_fmt_g" severity error;
162	
163	  --------------------------------------------
164	  -- Pipelined Implementation
165	  --------------------------------------------
166	  g_pipelined : if mode_g = "PIPELINED" generate
167	    signal X, Y     : IntArr_t(0 to iterations_g);
168	    signal Z        : AngArr_t(0 to iterations_g);
169	    signal Vld      : std_logic_vector(0 to iterations_g);
170	    signal Quad     : t_aslv2(0 to iterations_g);
171	    signal yQc, xQc : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
172	    signal QcVld    : std_logic;
173	  begin
174	    -- Pipelined implementation can take a sample every clock cycle
175	    rdy_i <= '1';
176	
177	    -- Implementation
178	    p_cordic_pipelined : process(clk_i)
179	    begin
180	      if rising_edge(clk_i) then
181	        if rst_i = '1' then
182	          Vld    <= (others => '0');
183	          vld_o <= '0';
184	          QcVld  <= '0';
185	        else
186	          -- Initialization
187	          X(0)    <= psi_fix_resize(dat_abs_i, in_abs_fmt_g, internal_fmt_g, round_g, sat_g);
188	          Y(0)    <= (others => '0');
189	          Z(0)    <= psi_fix_resize(dat_ang_i, in_angle_fmt_g, angle_int_fmt_g, round_g, psi_fix_wrap);
190	          Quad(0) <= psi_fix_resize(dat_ang_i, in_angle_fmt_g, QuadFmt_c, psi_fix_trunc, psi_fix_wrap);
191	          Vld(0)  <= vld_i;
192	
193	          -- Cordic iterations_g
194	          Vld(1 to Vld'high)   <= Vld(0 to Vld'high - 1);
195	          Quad(1 to Quad'high) <= Quad(0 to Quad'high - 1);
196	          for i in 0 to iterations_g - 1 loop
197	            X(i + 1) <= CordicStepX(X(i), Y(i), Z(i), i);
198	            Y(i + 1) <= CordicStepY(X(i), Y(i), Z(i), i);
199	            Z(i + 1) <= CordicStepZ(Z(i), i);
200	          end loop;
201	
202	          -- Quadrant Correction
203	          QcVld <= Vld(iterations_g);
204	          if (Quad(iterations_g) = "00") or (Quad(iterations_g) = "11") then
205	            yQc <= Y(iterations_g);
206	            xQc <= X(iterations_g);
207	          else
208	            yQc <= psi_fix_neg(Y(iterations_g), internal_fmt_g, internal_fmt_g, round_g, sat_g);
209	            xQc <= psi_fix_neg(X(iterations_g), internal_fmt_g, internal_fmt_g, round_g, sat_g);
210	          end if;
211	
212	          -- Output
213	          vld_o <= QcVld;
214	          if gain_comp_g then
215	            dat_inp_o <= psi_fix_mult(xQc, internal_fmt_g, GcCoef_c, GcFmt_c, out_fmt_g, round_g, sat_g);
216	            dat_qua_o <= psi_fix_mult(yQc, internal_fmt_g, GcCoef_c, GcFmt_c, out_fmt_g, round_g, sat_g);
217	          else
218	            dat_inp_o <= psi_fix_resize(xQc, internal_fmt_g, out_fmt_g, round_g, sat_g);
219	            dat_qua_o <= psi_fix_resize(yQc, internal_fmt_g, out_fmt_g, round_g, sat_g);
220	          end if;
221	        end if;
222	      end if;
223	    end process;
224	  end generate;
225	
226	  --------------------------------------------
227	  -- Serial Implementation
228	  --------------------------------------------
229	  g_serial : if mode_g = "SERIAL" generate
230	    signal Xin, Yin : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
231	    signal Zin      : std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0);
232	    signal XinVld   : std_logic;
233	    signal Quadin   : std_logic_vector(1 downto 0);
234	    signal X, Y     : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
235	    signal Z        : std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0);
236	    signal CordVld  : std_logic;
237	    signal IterCnt  : integer range 0 to iterations_g - 1;
238	    signal Quad     : std_logic_vector(1 downto 0);
239	    signal yQc, xQc : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
240	    signal QcVld    : std_logic;
241	  begin
242	    rdy_i <= not XinVld;
243	
244	    p_cordic_serial : process(clk_i)
245	    begin
246	      if rising_edge(clk_i) then
247	        if rst_i = '1' then
248	          XinVld  <= '0';
249	          IterCnt <= 0;
250	          vld_o  <= '0';
251	          CordVld <= '0';
252	        else
253	          -- Input latching
254	          if XinVld = '0' and vld_i = '1' then
255	            XinVld <= '1';
256	            Xin    <= psi_fix_resize(dat_abs_i, in_abs_fmt_g, internal_fmt_g, round_g, sat_g);
257	            Yin    <= (others => '0');
258	            Zin    <= psi_fix_resize(dat_ang_i, in_angle_fmt_g, angle_int_fmt_g, round_g, psi_fix_wrap);
259	            Quadin <= psi_fix_resize(dat_ang_i, in_angle_fmt_g, QuadFmt_c, psi_fix_trunc, psi_fix_wrap);
260	          end if;
261	
262	          -- CORDIC loop
263	          CordVld <= '0';
264	          if IterCnt = 0 then
265	            -- start of calculation
266	            if XinVld = '1' then
267	              X       <= CordicStepX(Xin, Yin, Zin, 0);
268	              Y       <= CordicStepY(Xin, Yin, Zin, 0);
269	              Quad    <= Quadin;
270	              Z       <= CordicStepZ(Zin, 0);
271	              IterCnt <= IterCnt + 1;
272	              XinVld  <= '0';
273	            end if;
274	          else
275	            -- Normal Calculation Step
276	            X <= CordicStepX(X, Y, Z, IterCnt);
277	            Y <= CordicStepY(X, Y, Z, IterCnt);
278	            Z <= CordicStepZ(Z, IterCnt);
279	
280	            if IterCnt = iterations_g - 1 then
281	              IterCnt <= 0;
282	              CordVld <= '1';
283	            else
284	              IterCnt <= IterCnt + 1;
285	            end if;
286	          end if;
287	
288	          -- Quadrant Correction
289	          QcVld <= CordVld;
290	          if (Quad = "00") or (Quad = "11") then
291	            yQc <= Y;
292	            xQc <= X;
293	          else
294	            yQc <= psi_fix_neg(Y, internal_fmt_g, internal_fmt_g, round_g, sat_g);
295	            xQc <= psi_fix_neg(X, internal_fmt_g, internal_fmt_g, round_g, sat_g);
296	          end if;
297	
298	          -- Output
299	          vld_o <= QcVld;
300	          if gain_comp_g then
301	            dat_inp_o <= psi_fix_mult(xQc, internal_fmt_g, GcCoef_c, GcFmt_c, out_fmt_g, round_g, sat_g);
302	            dat_qua_o <= psi_fix_mult(yQc, internal_fmt_g, GcCoef_c, GcFmt_c, out_fmt_g, round_g, sat_g);
303	          else
304	            dat_inp_o <= psi_fix_resize(xQc, internal_fmt_g, out_fmt_g, round_g, sat_g);
305	            dat_qua_o <= psi_fix_resize(yQc, internal_fmt_g, out_fmt_g, round_g, sat_g);
306	          end if;
307	
308	        end if;
309	      end if;
310	    end process;
311	  end generate;
312	
313	end architecture;
314	
